        changes.append("Slides added or removed.")
    if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
        changes.append("Animations changed.")
    if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
        changes.append("Transitions changed.")
    # For slide content (besides font size on title of second slide), check for modified slides
    # We will ignore the slide 2 title font size change; check other modifications
    allowed_slide_ids = set()
    if len(ppt_diff.modified_slides) > 0:
        # Find slide 2 id (in original)
        slide2_id = None
        if len(ppt_diff.added_slides) == 0 and len(ppt_diff.removed_slides) == 0:
            if len(ppt_diff.modified_slides) >= 1:
                # Try to find slide 2 by slide_number
                for s1, s2 in ppt_diff.modified_slides:
                    if getattr(s1, 'slide_number', None) == 2:
                        slide2_id = s1.slide_id
                        break
        for s1, s2 in ppt_diff.modified_slides:
            if slide2_id is not None and s1.slide_id == slide2_id:
                continue
            changes.append(f"Other content changed on slide {s1.slide_number if hasattr(s1, 'slide_number') else '?'}.")
    if changes:
        return f"Extraneous changes: {'; '.join(changes)}", 0.0
    return "No extraneous changes.", 1.0
